export const ecGeralData: ECGeralType[] = rawCsv
  .split('\n')
  .slice(1) // Pula o cabeçalho
  .map(line => line.split(';'))
  .filter(parts => parts.length >= 7) // Ignora linhas em branco ou mal formatadas
  .map(parts => ({
    ano: parts[0]?.trim() || '',
    processo: parts[1]?.trim() || '',
    origem: parts[2]?.trim() || '',
    assunto: parts[3]?.trim() || '',
    tipo: parts[4]?.trim() || '',
    sigla: parts[5]?.trim() || '',
    denominacao: parts[6]?.trim().replace(/^"|"$/g, '') || '', // Remove aspas
    decisao: parts[7]?.trim() || '',
    situacao: parts[8]?.trim() || '',
    observacao: parts[9]?.trim() || '',
  }));
